import axios from "axios";

const API = axios.create({
  baseURL: "http://127.0.0.1:5000",
  headers: {
    "Content-Type": "application/json",
  },
});

export const registerUser = (data) => API.post("/auth/register", data);
export const loginUser = (data) => API.post("/auth/login", data);
export const saveProfile = (data) => API.post("/profile/save", data);
export const getProfile = (userId) => API.get(`/profile/${userId}`);
export const saveVitals = (data) => API.post("/vitals/add", data);
export const sendChatMessage = (data) => API.post("/chat/message", data);
export const downloadReportPDF = (data) =>
  API.post("/chat/download-report", data, {
    responseType: "blob",
  });
